        // Navigate to the password reset screen with the token
        if let rootViewController = window.rootViewController as? UINavigationController {
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            if let passwordResetViewController = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
                passwordResetViewController.token = token
                rootViewController.pushViewController(passwordResetViewController, animated: true)
            }
        }
    }
